local StartCtrlBase = LXImport(".StartCtrlBase")
---guideType 1
---@class StartCtrlGuideStory
local StartCtrlGuideStory = LxClass("StartCtrlGuideStory", StartCtrlBase)

function StartCtrlGuideStory:StartCtrlGuideStory()

end

function StartCtrlGuideStory:OnSceneLoaded()
    self._doAfter = false

    --local isFinish = gModelGuideStory:IsGuideStoryFinish()
    local isFinish = false

    --if PRODUCT_G_VER ~= 0 then
    --    isFinish = true
    --end

    local toBattle = false
    if gModelBattle then
        toBattle = gModelBattle:CheckCacheOfflineCombat()
        if toBattle then
            isFinish = true
        end
    end
    GF.OpenWnd('UIMCity')

    if gModelPlayer:IsNoName() then
        GF.OpenWnd('UIPtNew') 
        return "LCityMap"
    end

    if not isFinish then
        self._doAfter = true
        FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, { index = LMainBtnIndexConst.ADVENTURE })
        return "LGuideStoryMap"
    end

    if not gModelFunctionOpen:CheckIsOpened(10000000, false) then
        FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, { index = LMainBtnIndexConst.ADVENTURE })
        return "LFightIdleMap"
    else
        return "LCityMap"
    end
end

function StartCtrlGuideStory:OnSceneEnterFinished(tobattle)
    local scene = LGameFunction.GetMainScene()
    local curMap = scene:GetCurMap()
    if curMap:GetMapClassName() == "LFightIdleMap" or curMap:GetMapClassName() == "LGuideStoryMap" then
        FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, { index = LMainBtnIndexConst.ADVENTURE })
    end

    -- if not self._doAfter then
    --     return
    -- end

    local wnd = GF.FindFirstWndByName("UIPtNew")
    if wnd then
        wnd:StartPlay()
    end
end

return StartCtrlGuideStory
